import React, { useEffect, useState } from "react";
import axios from "axios";

export default function MealPlan() {
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/dietplan/my-plans", {
        headers: {
          Authorization: "Bearer " + localStorage.getItem("token"),
        },
      })
      .then((res) => {
        setPlans(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return <h4 className="text-center mt-5">Loading your meal plan...</h4>;
  }

  if (plans.length === 0) {
    return <h4 className="text-center mt-5">No Meal Plans Yet</h4>;
  }

  return (
    <div className="container my-4">
      <h2 className="mb-4 text-center">Your AI Generated Meal Plan</h2>

      {plans.map((plan, index) => (
        <div key={index} className="card mb-4 shadow-sm">
          <div className="card-body">
            <h4 className="card-title">
              {plan.patientName}
            </h4>

            <p className="mb-1">
              <strong>Condition:</strong> {plan.condition}
            </p>
            <p className="mb-1">
              <strong>Goal:</strong> {plan.goal}
            </p>
            <p className="mb-3">
              <strong>Daily Calories:</strong> {plan.calories} kcal
            </p>

            {/* MEALS */}
            {Object.entries(plan.meals).map(([mealTime, items]) => (
              <div key={mealTime} className="mb-3">
                <h5 className="text-primary text-capitalize">
                  {mealTime}
                </h5>
                <ul className="list-group list-group-flush">
                  {items.map((food, i) => (
                    <li key={i} className="list-group-item">
                      {food.item} — <strong>{food.quantity}</strong>
                    </li>
                  ))}
                </ul>
              </div>
            ))}

            {/* AVOID FOODS */}
            {plan.avoid?.length > 0 && (
              <div className="mt-3">
                <h6 className="text-danger">Foods to Avoid</h6>
                <ul>
                  {plan.avoid.map((a, i) => (
                    <li key={i}>{a}</li>
                  ))}
                </ul>
              </div>
            )}

            {/* NOTES */}
            {plan.notes?.length > 0 && (
              <div className="mt-3">
                <h6 className="text-success">Health Notes</h6>
                <ul>
                  {plan.notes.map((n, i) => (
                    <li key={i}>{n}</li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        </div>
      ))}
    </div>
  );
}
